89	type DamageEntry = {
90	  itemType: string;
91	  amount: number;
92	};
93	
94	type Incident = {
95	  damages: DamageEntry[];
96	};
97	
98	const INSURANCE_VALUES: Record<string, number> = {
99	  sword: 1000,
100	  amulet: 600,
101	  staff: 800,
102	  potion: 400,
103	  rune: 250,
104	  moonstone: 250,
105	};
106	
107	const DEDUCTIBLE = 100;
108	const CLAIM_ENCHANTMENT_THRESHOLD = 8;
109	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
110	
111	const isHighEnchantment = (item: Item | undefined): boolean =>
112	  (item?.enchantment ?? 0) >= CLAIM_ENCHANTMENT_THRESHOLD;
113	
114	const reimbursableDamage = (item: Item | undefined, rawAmount: number): number => {
115	  const adjustedAmount = isHighEnchantment(item)
116	    ? rawAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
117	    : rawAmount;
118	  return adjustedAmount - DEDUCTIBLE;
119	};
120	
121	export function claim(items: Item[], incident: Incident, previousPayouts: number = 0) {
122	  const insuranceSum = items.reduce(
123	    (sum, item) => sum + INSURANCE_VALUES[item.type],
124	    0,
125	  );
126	  const cap = 2 * insuranceSum;
127	
128	  const totalPayout = incident.damages.reduce(
129	    (sum, damage) => {
130	      const matchingItem = items.find((item) => item.type === damage.itemType);
131	      return sum + reimbursableDamage(matchingItem, damage.amount);
132	    },
133	    0,
134	  );
135	
136	  const effectiveCap = cap - previousPayouts;
137	  const cappedPayout = Math.min(totalPayout, effectiveCap);
138	
139	  return { payout: cappedPayout, remainingCap: effectiveCap - cappedPayout };
140	}
